-- -----------------------------------------------------------------------------
-- VERIFICAÇÃO 1: contagem total de FKs criadas no schema
-- (esperado: 232)
-- -----------------------------------------------------------------------------
SELECT COUNT(*) AS total_fks FROM pg_constraint WHERE contype = 'f';

-- -----------------------------------------------------------------------------
-- VERIFICAÇÃO 2: lista FKs em estado NOT VALID
-- (esperado: zero linhas - todas validadas na criação)
-- -----------------------------------------------------------------------------
SELECT conrelid::regclass AS tabela, conname AS constraint_name
FROM pg_constraint
WHERE contype = 'f' AND NOT convalidated
ORDER BY 1, 2;
